DATA_DIR = "dados_persistentes"
os.makedirs(DATA_DIR, exist_ok=True)


def salvar_dados(nome, df):
    """Grava um DataFrame em disco para persistir entre sessões."""
    try:
        df.to_pickle(os.path.join(DATA_DIR, f"{nome}.pkl"))
    except Exception:
        pass


def carregar_dados(nome):
    """Recupera um DataFrame salvo, ou None se não existir."""
    caminho = os.path.join(DATA_DIR, f"{nome}.pkl")
    if os.path.exists(caminho):
        try:
            return pd.read_pickle(caminho)
        except Exception:
            return None
    return None


def limpar_dados_salvos():
    """Remove todos os dados persistidos em disco."""
    for f in os.listdir(DATA_DIR):
        try:
            os.remove(os.path.join(DATA_DIR, f))
        except Exception:
            pass

