def df_tarefas_vazio():
    df = pd.DataFrame(columns=TAREFA_COLS)
    df["ID"] = df["ID"].astype("int64")
    df["Prazo"] = pd.to_datetime(df["Prazo"])
    return df


def status_efetivo(row):
    """Status considerando atraso: prazo vencido e não concluída = Atrasada."""
    try:
        if (row["Status"] != "Concluída" and pd.notna(row["Prazo"])
                and pd.Timestamp(row["Prazo"]).date() < datetime.now().date()):
            return "Atrasada"
    except Exception:
        pass
    return row["Status"]

